def get_book_title(book_id):
    """Map book_id to display title for FTS."""
    titles = {
        4102: "1 Maccabees", 4009: "1 Maccabees",
        4103: "2 Maccabees", 4010: "2 Maccabees",
        4105: "Letter of Jeremiah", 4008: "Letter of Jeremiah",
        4001: "1 Esdras",
    }
    return titles.get(book_id, "Unknown")


def get_volume_title(volume_id):
    titles = {200: "Coptic Bible", 400: "Russian Orthodox Bible"}
    return titles.get(volume_id, "Unknown")


def insert_verses(conn, book_id, volume_id, verse_tuples, book_abbrev, max_id, max_ch_id):
    """Insert missing verses for a book. Returns (added_count, new_max_id, new_max_ch_id)."""
    # Build existing refs set
    existing = set()
    for row in conn.execute(
        "SELECT reference FROM verses WHERE book_id = ?", (book_id,)
    ):
        if row[0]:
            existing.add(row[0])

    # Build chapter map
    chapter_map = {}
    for row in conn.execute(
        "SELECT id, chapter_number FROM chapters WHERE book_id = ?", (book_id,)
    ):
        chapter_map[row[1]] = row[0]

    book_title = get_book_title(book_id)
    vol_title = get_volume_title(volume_id)
    added = 0

    for ch_num, verse_num, text in verse_tuples:
        ref = f"{book_abbrev} {ch_num}:{verse_num}"
        if ref in existing:
            continue

        # Ensure chapter exists
        if ch_num not in chapter_map:
            max_ch_id += 1
            chapter_map[ch_num] = max_ch_id
            conn.execute(
                "INSERT INTO chapters (id, book_id, chapter_number) VALUES (?, ?, ?)",
                (max_ch_id, book_id, ch_num),
            )

        max_id += 1
        ch_id = chapter_map[ch_num]

        conn.execute(
            "INSERT INTO verses (id, chapter_id, book_id, volume_id, verse_number, text, reference) VALUES (?, ?, ?, ?, ?, ?, ?)",
            (max_id, ch_id, book_id, volume_id, verse_num, text, ref),
        )
        conn.execute(
            "INSERT INTO scriptures_fts (rowid, text, reference, book_title, volume_title) VALUES (?, ?, ?, ?, ?)",
            (max_id, text, ref, book_title, vol_title),
        )
        added += 1

    return added, max_id, max_ch_id


def update_counts(conn):
    """Update num_verses in chapters and num_chapters in books."""
    conn.execute("""
        UPDATE chapters SET num_verses = (
            SELECT COUNT(*) FROM verses WHERE verses.chapter_id = chapters.id
        )
    """)
    for vid in (200, 400):
        conn.execute("""
            UPDATE books SET num_chapters = (
                SELECT COUNT(DISTINCT chapter_number) FROM chapters
                WHERE chapters.book_id = books.id
            ) WHERE volume_id = ?
        """, (vid,))


def main():
    if not os.path.exists(DB_PATH):
        print(f"ERROR: Database not found at {DB_PATH}")
        return

    conn = sqlite3.connect(DB_PATH)
    conn.execute("PRAGMA journal_mode=WAL")

    max_id = conn.execute("SELECT MAX(id) FROM verses").fetchone()[0] or 0
    max_ch_id = conn.execute("SELECT MAX(id) FROM chapters").fetchone()[0] or 0

    total_added = 0
    stats = []

    # --- 1 Maccabees (Coptic = 4102/200, Russian = 4009/400) ---
    for book_id, vol_id in [(4102, 200), (4009, 400)]:
        added, max_id, max_ch_id = insert_verses(
            conn, book_id, vol_id, MACCABEES_1_MISSING, "1 Maccabees", max_id, max_ch_id
        )
        total_added += added
        stats.append(f"  1 Maccabees (book {book_id}, vol {vol_id}): +{added} verses")

    # --- 2 Maccabees (Coptic = 4103/200, Russian = 4010/400) ---
    for book_id, vol_id in [(4103, 200), (4010, 400)]:
        added, max_id, max_ch_id = insert_verses(
            conn, book_id, vol_id, MACCABEES_2_MISSING, "2 Maccabees", max_id, max_ch_id
        )
        total_added += added
        stats.append(f"  2 Maccabees (book {book_id}, vol {vol_id}): +{added} verses")

    # --- Letter of Jeremiah (Coptic = 4105/200, Russian = 4008/400) ---
    for book_id, vol_id in [(4105, 200), (4008, 400)]:
        added, max_id, max_ch_id = insert_verses(
            conn, book_id, vol_id, LETTER_OF_JEREMIAH, "Letter of Jeremiah", max_id, max_ch_id
        )
        total_added += added
        stats.append(f"  Letter of Jeremiah (book {book_id}, vol {vol_id}): +{added} verses")

    # --- 1 Esdras (Russian = 4001/400) sparse chapters ---
    for ch_verses in [ESDRAS_1_CHAPTER_1_MISSING, ESDRAS_1_CHAPTER_3_MISSING, ESDRAS_1_CHAPTER_4_MISSING]:
        added, max_id, max_ch_id = insert_verses(
            conn, 4001, 400, ch_verses, "1 Esdras", max_id, max_ch_id
        )
        total_added += added
        if ch_verses:
            ch = ch_verses[0][0]
            stats.append(f"  1 Esdras ch.{ch} (book 4001, vol 400): +{added} verses")

    # Update counts
    update_counts(conn)

    # Rebuild FTS
    print("Rebuilding FTS index...")
    conn.execute("INSERT INTO scriptures_fts(scriptures_fts) VALUES('rebuild')")

    conn.commit()
    conn.close()

    print(f"\nDone! Total verses added: {total_added}")
    print("\nBreakdown:")
    for s in stats:
        print(s)

    # Print verification
    conn2 = sqlite3.connect(DB_PATH)
    print("\n--- Verification ---")
    for book_id, name in [(4102, "1 Macc Coptic"), (4009, "1 Macc Russian"),
                           (4103, "2 Macc Coptic"), (4010, "2 Macc Russian"),
                           (4105, "EpJer Coptic"), (4008, "EpJer Russian"),
                           (4001, "1 Esdras Russian")]:
        rows = conn2.execute(
            "SELECT c.chapter_number, COUNT(v.id) FROM chapters c LEFT JOIN verses v ON v.chapter_id=c.id WHERE c.book_id=? GROUP BY c.chapter_number ORDER BY c.chapter_number",
            (book_id,)
        ).fetchall()
        total_v = sum(r[1] for r in rows)
        ch_list = ", ".join(f"ch{r[0]}({r[1]}v)" for r in rows)
        print(f"  {name} (id={book_id}): {len(rows)} chapters, {total_v} verses — {ch_list}")
    conn2.close()


if __name__ == "__main__":
    main()
